/**
 * Minimal Liveblocks types for the active-users-list task. The room only
 * tracks presence (which is empty by default) and per-user info — the page
 * does not write any Storage state.
 */
export type Presence = Record<string, never>;

export type Storage = Record<string, never>;

export type UserMeta = {
  id?: string;
  info?: { name?: string };
};

declare global {
  interface Liveblocks {
    Presence: Presence;
    Storage: Storage;
    UserMeta: UserMeta;
  }
}

export {};

"use client";

import {
  LiveblocksProvider,
  RoomProvider,
  ClientSideSuspense
} from "@liveblocks/react/suspense";
import type { ReactNode } from "react";

export function Room({ roomId, children }: { roomId: string; children: ReactNode }) {
  return (
    <LiveblocksProvider authEndpoint="/api/liveblocks-auth">
      <RoomProvider id={roomId}>
        <ClientSideSuspense fallback={<div>Loading…</div>}>
          {() => <>{children}</>}
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

"use client";

import { useParams } from "next/navigation";
import { Room } from "./Room";

// TODO: implement the active-users-list requirements described in
// instruction.md. The Room wrapper below already provides LiveblocksProvider
// and RoomProvider; you must use the Liveblocks React presence hooks to
// render the active user count and the per-user rows as described by the
// task instruction. See instruction.md for the exact DOM contract
// (element ids, testids, data-connection-id, and badge styling).

function ActiveUsersView() {
  return (
    <main style={{ padding: 24, fontFamily: "system-ui" }}>
      <h1>Active Users</h1>
      {/* TODO(presence): render the active-users DOM per instruction.md. */}
    </main>
  );
}

export default function UsersPage() {
  const params = useParams<{ room: string }>();
  const roomId =
    (Array.isArray(params?.room) ? params?.room[0] : params?.room) ||
    "default-room";

  return (
    <Room roomId={roomId}>
      <ActiveUsersView />
    </Room>
  );
}

import { Liveblocks } from "@liveblocks/node";
import { NextResponse } from "next/server";

const secret = process.env.LIVEBLOCKS_SECRET_KEY;

export async function POST(request: Request) {
  if (!secret) {
    return NextResponse.json(
      { error: "Missing LIVEBLOCKS_SECRET_KEY" },
      { status: 500 }
    );
  }

  let body: { room?: string } = {};
  try {
    body = await request.json();
  } catch {
    body = {};
  }
  const room = typeof body?.room === "string" ? body.room : "default-room";

  const liveblocks = new Liveblocks({ secret });
  const session = liveblocks.prepareSession(
    `user-${Math.random().toString(36).slice(2, 10)}`,
    { userInfo: { name: "anonymous" } }
  );
  session.allow(room, session.FULL_ACCESS);

  const { status, body: tokenBody } = await session.authorize();
  return new NextResponse(tokenBody, {
    status,
    headers: { "content-type": "application/json" }
  });
}

import Link from "next/link";

export default function Home() {
  return (
    <main style={{ padding: 24 }}>
      <h1>Liveblocks Active Users</h1>
      <p>
        Open <Link href="/users/demo">/users/demo</Link> to see who is
        connected to the demo room.
      </p>
    </main>
  );
}

import React from "react";

export const metadata = {
  title: "Liveblocks Active Users",
  description: "Live list of users connected to a Liveblocks room"
};

export default function RootLayout({
  children
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}

